create table dirkspzm32.isi_com_server (
    sid              varchar2(2 char) not null enable,
    firma_nr         number(2, 0) not null enable,
    com_name         varchar2(15 char) not null enable,
    com_text         varchar2(30 char),
    com_adress       varchar2(15 char) not null enable,
    com_port         number(5, 0) not null enable,
    com_sendto       number(5, 0),
    com_connected    varchar2(1 char) default 'F' not null enable,
    com_connect      varchar2(1 char) default 'F',
    com_computername varchar2(30 char),
    com_ort_beschr   varchar2(500 char),
    com_visuname     varchar2(15 char),
    com_geraet_typ   varchar2(10 char),
    com_geraet_name  varchar2(255 char)
);

alter table dirkspzm32.isi_com_server
    add constraint pk_isi_com_server
        primary key ( sid,
                      firma_nr,
                      com_name )
            using index enable;


